import { useEffect, useState } from "react";

function Admin() {

    const [application, setApplication] = useState([]);
    const [search, setSearch] = useState("");
    const [filter, setFilter] = useState("");

    useEffect(() => {
        fetch("http://localhost:5000/application", {
            headers: {
                Authorization: `Bearer ${localStorage.getItem("token")}`
            }

        })
        .then(res => res.json())
        .then(data => setApplication(data))
    }, []);

    const updateStatus = async (id, status) => {

        const response = await fetch( `http://localhost:5000/update-status/${id}`,
            {
                 method: "PUT",
                 headers: {"Content-Type": "application/json"},
                body: JSON.stringify({ status })
            }
        );
        const data = await response.json();
        alert(data.message);
        window.location.reload();
    };

 return (
        <div className="container">
            <h2>Admin Panel</h2>
            <input
                type="text"
                placeholder="Search by name or course"
                onChange={(e) => setSearch(e.target.value)}
            />
            <br /><br />
            <select onChange={(e) => setFilter(e.target.value)}>
                <option value="">All</option>
                <option value="approved">Approved</option>
                <option value="rejected">Rejected</option>
                <option value="pending">Pending</option>
            </select>
            <br /><br />

            <table border="1" cellPadding="10" width="100%">
                <thead>
                    <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Course</th>
                        <th>Status</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    {
                        application.filter((item) => {return (
                            item.name.toLowerCase().includes(search.toLowerCase()) ||
                             item.course.toLowerCase().includes(search.toLowerCase())
                            )
                        })
                        .filter((item) => {
                            if (filter === "") {
                                return true;
                            }
                            return item.status === filter;
                        })
                        .map((item, index) => (
                            <tr key={index}>
                                <td>{item.name}</td>
                                <td>{item.email}</td>
                                <td>{item.course}</td>
                                <td>
                                    <span
                                        style={{
                                            color:item.status === "approved" ? "green"
                                             : item.status === "rejected"? "red" : "orange"
                                        }} >
                                             {item.status}
                                    </span>
                                </td>
                                <td>
                                    <div className="action-btns">
                                        <button onClick={() =>updateStatus(item._id, "approved")
                                            }>
                                            Approve
                                        </button>
                                        <button onClick={() =>updateStatus(item._id, "rejected") }>
                                            Reject
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))
                    }
                </tbody>
            </table>
        </div>
    );
}
export default Admin;
